// Extraer contexto del error para el resto del handler
const errorData = $input.first().json;

// n8n Error Trigger expone: execution, workflow, error
const execution = errorData.execution || {};
const workflow  = errorData.workflow  || {};
const error     = errorData.error     || {};

// Intentar extraer remote_jid del contexto de ejecución
// n8n guarda el último item procesado en execution.data.resultData
let remoteJid = null;
let payloadStr = null;

try {
  const runData = execution?.data?.resultData?.runData || {};
  // Buscar en el primer nodo que procesó datos (Extraer y Validar)
  const extractNode = runData['Code — Extraer y Validar'] ||
                      runData['Code — Redis Batch (paralelo)'];
  if (extractNode) {
    const firstRun = extractNode[0]?.data?.main?.[0]?.[0]?.json;
    remoteJid = firstRun?.remote_jid || null;
    payloadStr = JSON.stringify(firstRun || {});
  }
} catch(e) {
  // No se pudo extraer JID — registrar igualmente sin liberar lock
}

const errorMessage = error.message || 'Error desconocido';
const errorStack   = error.stack   || '';
const nodeName     = error.node?.name || 'nodo desconocido';
const workflowName = workflow.name || 'Bot Admisión';
const executionId  = execution.id  || 'unknown';

return [{
  json: {
    remote_jid:    remoteJid,
    has_jid:       !!remoteJid,
    error_message: errorMessage,
    error_stack:   errorStack.slice(0, 2000),
    failed_node:   nodeName,
    workflow_name: workflowName,
    execution_id:  executionId,
    payload:       payloadStr,
    failed_at:     new Date().toISOString()
  }
}];

// Sin JID disponible — solo loguear en Postgres sin intentar liberar lock
const ctx = $('Code — Parse Error Context').first().json;
return [{
  json: {
    note: 'No se pudo extraer JID. Lock no liberado. Registrando en DLQ igualmente.',
    execution_id: ctx.execution_id,
    failed_node: ctx.failed_node,
    error_message: ctx.error_message
  }
}];

